using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
ITransformer? trainedModel = null;

app.MapGet("/", () => "ChurnPredictor API — POST /predict or POST /train");

app.MapPost("/train", () =>
{
    var data = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

    var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(CustomerData.Age),
            nameof(CustomerData.Income),
            "RegionEncoded",
            nameof(CustomerData.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
            labelColumnName: nameof(CustomerData.Label),
            featureColumnName: "Features"));

    trainedModel = pipeline.Fit(data);
    mlContext.Model.Save(trainedModel, data.Schema, modelPath);

    // Evaluate on training data (small dataset — cross-validation omitted)
    var predictions = trainedModel.Transform(data);
    var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: nameof(CustomerData.Label));

    return Results.Ok(new
    {
        Message = "Model trained and saved.",
        metrics.Accuracy,
        metrics.AreaUnderRocCurve,
        metrics.F1Score
    });
});

app.MapPost("/predict", (CustomerInput input) =>
{
    if (trainedModel is null)
    {
        if (!File.Exists(modelPath))
            return Results.BadRequest(new { Error = "Model not trained yet. POST /train first." });
        trainedModel = mlContext.Model.Load(modelPath, out _);
    }

    var engine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(trainedModel);
    var prediction = engine.Predict(new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    });

    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Confidence = prediction.Probability
    });
});

app.Run();

// --- Data models ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }

    [LoadColumn(4), ColumnName("Label")]
    [BooleanType]
    public bool Label { get; set; }
}

// Maps "Yes"/"No" in CSV → bool Label
[AttributeUsage(AttributeTargets.Property)]
public class BooleanTypeAttribute : Attribute { }

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")] public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
    public float Score { get; set; }
}

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

